section.sourcecode:
if record cannot be safely parsed, its version is unsupported,
   or required authentication is absent:
    fail closed without ordinary release
else if predecessor_invalid:
    state = EFFECT_ACK_BLOCK
else if deadline_exceeded:
    state = EFFECT_ACK_BLOCK
else if not effect_checkable_reception:
    state = EFFECT_NACK
else if integrity_failure:
    state = EFFECT_ACK_BLOCK
else if connection_decision == BLOCK:
    state = EFFECT_ACK_BLOCK
else if connection_decision == ISOLATE:
    state = EFFECT_ACK_ISOLATE
else if connection_decision == RELEASE
        and CoreDone(record with candidate state EFFECT_ACK_DONE):
    state = EFFECT_ACK_DONE
else:
    state = EFFECT_ACK_CONTINUE

ordinary_release = (state == EFFECT_ACK_DONE)

effect-ack-record = { wire_version: 1, message_type: "effect-ack-record", protocol_root_id: bounded-id, protocol_version: positive-int, protocol_id: bounded-protocol-id, previous_protocol_id: bounded-protocol-id / null, previous_protocol_hash: sha256-id / null, protocol_hash: sha256-id, input_id: bounded-id, input_hash: sha256-id / "UNAVAILABLE", state: effect-state, transport_ack: bool, origin_checked: bool, context_checked: bool, semantics_reconstructed: bool, effect_anticipated: bool, risk_classified: bool, risk_level: risk-level, responsibility_assigned: bool, responsibility_owner: bounded-owner, connection_decided: bool, connection_decision: connection-decision, policy_id: bounded-id, policy_version: positive-int, policy_hash: sha256-id, policy_allows_release: bool, ordinary_release: bool, evaluation_timeout_ms: positive-timeout, deadline_exceeded: bool, reasons: text-set, evidence_refs: digest-set, required_evidence_refs: digest-set, open_questions: text-set, next_required_checks: text-set, created_utc: utc-timestamp, }
effect-state = "EFFECT_NACK" / "EFFECT_ACK_CONTINUE" / "EFFECT_ACK_DONE" / "EFFECT_ACK_ISOLATE" / "EFFECT_ACK_BLOCK"
risk-level = "UNKNOWN" / "LOW" / "MEDIUM" / "HIGH" / "CRITICAL"
connection-decision = "UNDECIDED" / "CONTINUE" / "RELEASE" / "ISOLATE" / "BLOCK"
sha256-id = tstr .regexp "^sha256:[0-9a-f]{64}$" bounded-id = tstr bounded-protocol-id = tstr bounded-owner = tstr positive-int = 1..9007199254740991 positive-timeout = 1..2147483647 utc-timestamp = tstr text-set = [*128 bounded-text] digest-set = [*128 sha256-id] bounded-text = tstr
effect-ack-capabilities = { message_type: "effect-ack-capabilities", supported_versions: [1* uint], }
